import { 運筆 } from '../bi.js';
// 開臉：面輪＋五官＋白毫（格網自帶：白毫12・鼻端16・頦20）
export function 菩薩開臉(bi) {
    const { M, L, Qk, C, S, 骨, 細, 以 } = 運筆(bi);
    const W_OUT = bi.W_OUT;
    // 面輪（豐頰圓頤）
    骨(() => {
        M(-5.05, 9.4);
        C(-5.35, 11.4, -5.45, 13.6, -5.0, 15.9);
        C(-4.55, 18.2, -3.3, 19.75, 0, 20.5);
        C(3.3, 19.75, 4.55, 18.2, 5.0, 15.9);
        C(5.45, 13.6, 5.35, 11.4, 5.05, 9.4);
        S();
    });
    // 二重頦：頤下一弧（図樣之相）
    細(() => bi.dim(0.7, () => { M(-1.5, 19.55); Qk(0, 20.0, 1.5, 19.55); S(); }));
    細(() => {
        // 眉：初月高懸
        M(-0.85, 12.25);
        Qk(-2.6, 11.4, -4.45, 12.35);
        S();
        M(0.85, 12.25);
        Qk(2.6, 11.4, 4.45, 12.35);
        S();
        // 上瞼長弓：大眼角一指，小眼角四指，弓背向上而末梢垂（此線獨重）
        以(W_OUT * 0.19, () => {
            M(-0.95, 14.0);
            Qk(-2.35, 13.35, -3.95, 14.25);
            S();
            M(0.95, 14.0);
            Qk(2.35, 13.35, 3.95, 14.25);
            S();
        });
        // 垂目之瞳：弓下微露
        bi.A(-2.35, 14.0, 0.4, Math.PI * 0.12, Math.PI * 0.88);
        bi.A(2.35, 14.0, 0.4, Math.PI * 0.12, Math.PI * 0.88);
        // 下瞼平收，目遂垂簾
        bi.dim(0.8, () => { M(-1.35, 14.5); Qk(-2.45, 14.72, -3.6, 14.48); S(); M(1.35, 14.5); Qk(2.45, 14.72, 3.6, 14.48); S(); });
        // 鼻：樑自目間而下，翼有一轉，孔在翼中不另筆
        M(-0.55, 13.6);
        C(-0.62, 14.3, -0.7, 14.95, -0.88, 15.5);
        Qk(-1.4, 15.95, -1.05, 16.3);
        S();
        M(0.55, 13.6);
        C(0.62, 14.3, 0.7, 14.95, 0.88, 15.5);
        Qk(1.4, 15.95, 1.05, 16.3);
        S();
        // 人中
        M(0, 16.75);
        L(0, 17.2);
        S();
        // 唇靜：上唇弓、合線獨重而平、下唇淡收
        M(-1.1, 17.5);
        Qk(-0.45, 17.28, -0.15, 17.46);
        S();
        M(1.1, 17.5);
        Qk(0.45, 17.28, 0.15, 17.46);
        S();
        以(W_OUT * 0.19, () => { M(-1.2, 17.9); Qk(0, 18.15, 1.2, 17.9); S(); });
        bi.dim(0.8, () => { M(-0.85, 18.55); Qk(0, 18.9, 0.85, 18.55); S(); });
    });
    // 白毫：頂下十二指，右旋
    bi.dot(0, 12.1, 0.28);
    細(() => bi.A(0, 12.1, 0.5));
}
// 耳：輪郭有折，垂埵穿璫（相好：耳厚垂埵）
export function 垂埵耳(bi) {
    const { M, Qk, C, S, 衣, 細 } = 運筆(bi);
    衣(() => {
        for (const d of [-1, 1]) {
            M(d * 5.0, 12.2);
            C(d * 6.6, 12.3, d * 6.75, 13.6, d * 6.5, 14.7);
            C(d * 6.3, 15.7, d * 5.95, 16.5, d * 5.8, 17.4);
            Qk(d * 5.7, 18.6, d * 5.85, 19.5);
            S();
            細(() => {
                M(d * 5.45, 13.0);
                Qk(d * 6.1, 13.4, d * 5.95, 14.55);
                S(); // 耳輪內折
                bi.A(d * 5.15, 15.0, 0.32, 0, 7); // 耳珠
                bi.A(d * 5.6, 19.9, 0.58);
                bi.dot(d * 5.6, 20.55, 0.2); // 耳璫
            });
        }
    });
}
// 頸三道（相好：三道）
export function 頸三道(bi) {
    const { M, Qk, S, 細 } = 運筆(bi);
    細(() => {
        M(-2.4, 22.3);
        Qk(0, 23.0, 2.4, 22.3);
        S();
        M(-2.6, 23.3);
        Qk(0, 24.05, 2.6, 23.3);
        S();
    });
}
